#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=6e5+10;
int ch[N][26],len[N],fa[N],lst=1,cnt=1,C[N];char s[N];long long ans[26];
inline void ins(int c)
{
	int p=lst, np=lst=++cnt;len[np]=len[p]+1;
	for(;p&&!ch[p][c];p=fa[p])ch[p][c]=np;C[np]=c;
	if(!p)fa[np]=1;
 	else
 	{
 		int v=ch[p][c];
 		if(len[v]==len[p]+1)fa[np]=v;
 		else
 		{
 			int nv=++cnt;len[nv]=len[p]+1;
 			fa[nv]=fa[v];memcpy(ch[nv],ch[v],sizeof(ch[v]));
 			for(;p&&ch[p][c]==v;p=fa[p])ch[p][c]=nv;
 			fa[np]=fa[v]=nv;C[nv]=C[v];
		}
	}
}
int main()
{
	scanf("%s",s);int n=strlen(s);drep(n-1,0,i)ins(s[i]-'a');
	rep(2,cnt,i)ans[C[i]]+=len[i]-len[fa[i]];rep(0,25,i)printf("%lld ",ans[i]);return 0;
}
